let tipIndex = 0;

let tips = [];
tips[0] = "צאו להליכה של 20 דקות בלי אוזניות ובלי גלילה בטלפון.";
tips[1] = "קחו בקבוק מים ושבו כמה דקות במקום ירוק ורגוע.";
tips[2] = "קבעו עם חבר סיבוב קצר בחוץ במקום עוד שיחה בוואטסאפ.";
tips[3] = "צאו לראות שקיעה במקום קרוב לבית.";
tips[4] = "בחרו פארק קרוב וצאו אליו גם אם יש לכם רק חצי שעה.";

let places = [];
places[0] = "פארק הירקון - מתאים להליכה קצרה, רכיבה או ישיבה ליד המים.";
places[1] = "גן לאומי אפולוניה - מתאים למשפחות ולמי שאוהב נוף לים.";
places[2] = "חוף השרון - מתאים לתצפית שקטה ולשקיעה.";
places[3] = "פארק רעננה - מתאים לפיקניק קצר או סיבוב רגוע.";
places[4] = "חורשת טבע קרובה לבית - פתרון טוב כשאין הרבה זמן.";

function showTip() {
    document.getElementById("tipResult").innerHTML = tips[tipIndex];

    tipIndex = tipIndex + 1;

    if (tipIndex === tips.length) {
        tipIndex = 0;
    }
}

function showPlaces() {
    let text = "";

    for (let i = 0; i < places.length; i++) {
        text = text + "<li>" + places[i] + "</li>";
    }

    document.getElementById("placesList").innerHTML = text;
}

function checkTime() {
    let minutes = parseInt(document.getElementById("timeText").value);

    if (minutes > 0 && minutes <= 30) {
        document.getElementById("recommendationResult").innerHTML =
            "יש לך זמן קצר: כדאי לצאת להליכה קצרה בפארק קרוב או לשבת כמה דקות במקום ירוק.";
    }
    else {
        if (minutes > 30 && minutes <= 90) {
            document.getElementById("recommendationResult").innerHTML =
                "יש לך זמן בינוני: אפשר לצאת לפיקניק קטן, תצפית או מסלול קצר ליד הבית.";
        }
        else {
            if (minutes > 90) {
                document.getElementById("recommendationResult").innerHTML =
                    "יש לך מספיק זמן: אפשר לבחור מסלול טבע קצר, גן לאומי או בילוי ארוך יותר עם חברים.";
            }
            else {
                document.getElementById("recommendationResult").innerHTML =
                    "יש להזין מספר דקות תקין.";
            }
        }
    }
}

function showAreaTip() {
    document.getElementById("areaResult").innerHTML =
        "אם אתם רוצים ירוק, מים ונחלים - התחילו מהצפון. אם אתם רוצים משהו קרוב ונגיש - המרכז. אם בא לכם נוף פתוח ושקט - הדרום.";
}

function showSeasonTip() {
    document.getElementById("seasonResult").innerHTML =
        "בקיץ מומלץ לבחור מסלול עם מים או צל. בחורף כדאי לבחור תצפיות ומדבר. באביב הכל פורח, ובסתיו מזג האוויר הכי נוח לטיול.";
}

function showShortTip() {
    document.getElementById("shortResult").innerHTML =
        "בחרו פארק, חורשה או תצפית קרובה לבית. גם חצי שעה בחוץ יכולה לתת תחושה של ניתוק מהמסך.";
}
